    public static long solve(long[] nums) {
        long[] abs = new long[nums.length];
        for (int i = 0; i < nums.length; i++) {
            abs[i] = Math.abs(nums[i]);
        }
        Arrays.sort(abs);
        long count = 0;
        for (int i = 0; i < abs.length; i++) {
            long target = 2 * abs[i];
            int left = i + 1;
            int right = abs.length - 1;
            int res = abs.length;
            while (left <= right) {
                int mid = (left + right) / 2;
                if (abs[mid] > target) {
                    res = mid;
                    right = mid - 1;
                } else {
